import{_ as t,o,c as a,a3 as n}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"59. Parental Leave","description":"","frontmatter":{"title":"59. Parental Leave","eba":"Health Allied & Managers Admin 2021-2025","topics":["leave","parental-leave","wages","superannuation"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/leave/59-parental-leave.md","filePath":"ebas/has-managers-admin/common-terms/leave/59-parental-leave.md"}'),i={name:"ebas/has-managers-admin/common-terms/leave/59-parental-leave.md"};function r(s,e,l,p,h,g){return o(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="_59-parental-leave" tabindex="-1">59. Parental Leave <a class="header-anchor" href="#_59-parental-leave" aria-label="Permalink to &quot;59. Parental Leave&quot;">​</a></h1><p>This clause deals with parental leave, including paid parental leave. The issue of superannuation and parental leave (both paid and unpaid) is addressed at clause 31.7.</p><p><strong>59.1</strong> Structure of clause This clause is structured as follows:</p><p><strong>(a)</strong> Definitions: subclause 59.2;</p><p><strong>(b)</strong> Long parental leave – unpaid: subclause 59.3;</p><p><strong>(c)</strong> Short parental leave – unpaid: subclause 59.4;</p><p><strong>(d)</strong> Paid parental leave: subclause 59.5;</p><p><strong>(e)</strong> Notice and evidence requirements: subclause 59.6;</p><p><strong>(f)</strong> Parental leave associated with the birth of a Child – additional provisions: subclause 59.7;</p><p><strong>(g)</strong> Unpaid pre-adoption leave: subclause 59.8;</p><p><strong>(h)</strong> Where placement does not proceed or continue: subclause 59.9;</p><p><strong>(i)</strong> Special maternity leave: subclause 59.10;</p><p><strong>(j)</strong> Variation of period of unpaid parental leave up to 12 months: subclause 59.11;</p><p><strong>(k)</strong> Right to request extension of period of unpaid parental leave beyond 12 months: subclause 59.12;</p><p><strong>(l)</strong> Parental leave and other entitlements: subclause 59.13;</p><p><strong>(m)</strong> Transfer to a safe job: subclause 59.14;</p><p><strong>(n)</strong> Returning to work after a period of parental leave: subclause 59.15;</p><p><strong>(o)</strong> Replacement Employees: subclause 59.16;</p><p><strong>(p)</strong> Communication during parental leave – organisational change: subclause 59.17; and</p><p><strong>(q)</strong> Keeping in touch days: subclause 59.18. Other provisions associated with parental leave are also included in this Agreement. Specifically, prenatal leave at <a href="/eba/ebas/has-managers-admin/common-terms/leave/57-pre-natal-leave.html">clause 57</a>, flexible working arrangements which includes the right to request to return from parental leave on a part-time basis at <a href="/eba/ebas/has-managers-admin/common-terms/preliminary/13-individual-flexibility-arrangement.html">clause 13</a>, leave to attend interviews and examinations relevant to adoption leave (preadoption leave) at clause 58 and breastfeeding at <a href="/eba/ebas/has-managers-admin/common-terms/leave/60-breastfeeding.html">clause 60</a>.</p><p><strong>59.2</strong> Definitions For the purposes of this clause:</p><p><strong>(a)</strong> Child means:</p><p><strong>(i)</strong> in relation to birth-related leave, a child (or children from a multiple birth) of the Eligible Employee or the Eligible Employee&#39;s Spouse; or</p><p><strong>(ii)</strong> in relation to adoption-related leave, a child (or children) under 16 (as at the day of placement or expected day of placement) who is placed or who is to be placed with the Eligible Employee for the purposes of adoption, other than a child or step-child of the Eligible Employee or of the Spouse of the Eligible Employee or a child who has previously lived continuously with the Eligible Employee for a period of six months or more (Adopted Child);</p><p><strong>(iii)</strong> as the case requires, includes a Stillborn Child.</p><p><strong>(b)</strong> Continuous Service includes:</p><p><strong>(i)</strong> continuous service with one and the same Employer or</p><p><strong>(ii)</strong> continuous service with more than one Employer including Institutions or Statutory Bodies (as defined at subclause 61.1(b)),</p><p><strong>(iii)</strong> includes any period of employment that would count as service under the Act, and</p><p><strong>(iv)</strong> an Allowable Period as defined in Section 1, Clause 61.1(b)(i).</p><p><strong>(c)</strong> Eligible Casual Employee means a casual Employee that has been employed by the Employer on a regular and systematic basis for a sequence of periods of employment during a period of at least 12 months and who has, but for the birth or expected birth of a Child or the decision to adopt a Child, a reasonable expectation of continuing engagement by the Employer on a regular and systematic basis.</p><p><strong>(d)</strong> Eligible Employee for the purposes of this <a href="/eba/ebas/has-managers-admin/common-terms/leave/55-personal-leave.html">clause 55</a> means an Employee who has at least six months&#39; Continuous Service or an Eligible Casual Employee as defined above.</p><p><strong>(e)</strong> Employee Couple has the same meaning as under the Act.</p><p><strong>(f)</strong> Flexible Long Parental Leave means the 30 days&#39; unpaid parental leave an Eligible Employee may take under subclause 59.3(g) as part of their 52 weeks&#39; entitlement of Long Parental Leave.</p><p><strong>(g)</strong> Long Parental Leave means the 52 weeks&#39; parental leave an Eligible Employee may take under subclause 59.3. A person taking Long Parental Leave under subclause 59.3(a)-59.3(e) is the Primary Carer for this period for the purpose of this clause.</p><p><strong>(h)</strong> Notional Flexible Period is the period during which the Eligible Employee would be on Flexible Long Parental Leave if the Eligible Employee took leave for all of the Eligible Employee&#39;s notified flexible days in a single continuous period.</p><p><strong>(i)</strong> Primary Carer means the person who has responsibility for the care of the Child. Only one person can be the Child&#39;s Primary Carer on a particular day.</p><p><strong>(j)</strong> Short Parental Leave means the up to eight weeks&#39; concurrent parental leave an Eligible Employee who will not be the Primary Carer of a Child may take under subclause 59.4 (Short Parental Leave – Unpaid).</p><p><strong>(k)</strong> Spouse includes a person to whom the Eligible Employee is married and a de facto partner, former spouse or former de facto spouse of the Employee. A de facto Spouse means a person who lives with the Employee as husband, wife or same-sex partner on a bona fide domestic basis.</p><p><strong>(l)</strong> Stillbirth means the delivery of a Stillborn Child.</p><p><strong>(m)</strong> Stillborn Child means:</p><p><strong>(i)</strong> a child who weighs at least 400 grams at delivery or whose period of gestation was at least 20 weeks; and</p><p><strong>(ii)</strong> who has not breathed since delivery; and</p><p><strong>(iii)</strong> whose heart has not beaten since delivery.</p><p><strong>59.3</strong> Long Parental Leave – Unpaid</p><p><strong>(a)</strong> An Eligible Employee is entitled to 12 months&#39; unpaid Long Parental Leave if:</p><p><strong>(i)</strong> the leave is associated with: <strong>(A)</strong> the birth of a Child (including a Stillbirth) of the Eligible Employee or the Eligible Employee&#39;s Spouse; or</p><p><strong>(B)</strong> the placement of a Child with the Eligible Employee for adoption; and</p><p><strong>(ii)</strong> the Eligible Employee is the Primary Carer, or in the case of a Stillbirth, the Eligible Employee would have been the Primary Carer if the Child had been born alive.</p><p><strong>(b)</strong> Except as provided at subclause 59.3(g) (Flexible Long Parental Leave) and subclause 59.18 (Keeping in Touch Days), the Eligible Employee must take the leave in a single continuous period.</p><p><strong>(c)</strong> Where an Eligible Employee is a member of an Employee Couple, except as provided at subclauses 59.3(g) (Flexible Long Parental Leave) and 59.4 (Short Parental Leave – Unpaid), parental leave must be taken by only one parent of an Employee Couple at a time in a single continuous period.</p><p><strong>(d)</strong> Each member of an Employee Couple may take a separate period of up to 12 months of Long Parental Leave. The period of Long Parental Leave will be reduced by any period of Short Parental Leave taken by the Eligible Employee.</p><p><strong>(e)</strong> Subject to subclause 59.3(f), an Eligible Employee may be able to extend a period of unpaid parental leave in accordance with subclause 59.11 (Variation of period of unpaid parental leave (up to 12 months)).</p><p><strong>(f)</strong> An Eligible Employee’s entitlement to Long Parental Leave (other than Flexible Long Parental Leave) will end on the first day that the Eligible Employee takes Flexible Long Parental Leave. This means that if an Eligible Employee intends on taking a period of continuous unpaid parental leave they must do so before they take any Flexible Long Parental Leave.</p><p><strong>(g)</strong> Flexible Long Parental Leave</p><p><strong>(i)</strong> An Eligible Employee may take up to 30 days of their Long Parental Leave entitlement (Flexible Long Parental Leave) during the 24-month period starting on the date of birth (including a Stillbirth) or day of placement of the Child if the requirements of this sub-clause are satisfied in relation to the leave.</p><p><strong>(ii)</strong> The number of days of Flexible Long Parental Leave that the Eligible Employee takes must not be more than the number of flexible days notified to the Employer under sub- clause 59.6(e)(iii) (subject to any agreement under sub- clause 59.6(e)(iv)).</p><p><strong>(iii)</strong> An Eligible Employee must take the Flexible Long Parental Leave as: <strong>(A)</strong> a single continuous period of one or more days; or <strong>(B)</strong> separate periods of one or more days each.</p><p><strong>(iv)</strong> An Eligible Employee may take the Flexible Long Parental Leave whether or not they have taken unpaid Long Parental Leave under subclause 59.3(b).</p><p><strong>(v)</strong> An Eligible Employee may take Flexible Long Parental Leave after taking one or more periods of unpaid Long Parental Leave under subclause 59.3(b) only if the total of those periods (disregarding any extension under sub-clause</p><p><strong>59.11</strong> or 59.12) is no longer than 12 months, less the employee&#39;s Notional Flexible Period, provided that the calculation is based on the assumption that: <strong>(A)</strong> the Eligible Employee ordinarily works each day that is not a Saturday or Sunday; and <strong>(B)</strong> there are no public holidays during the period.</p><p><strong>(vi)</strong> A member of an Employee Couple (the first employee) may take Flexible Long Parental Leave on the same day as the other member of the Employee Couple (the other employee) is taking unpaid Long Parental Leave only if the total of all periods of unpaid parental leave the first employee takes at the same time as the other employee is no longer than 8 weeks.</p><p><strong>(h)</strong> Hospitalised children – agreement to not take unpaid Long Parental Leave</p><p><strong>(i)</strong> If: <strong>(A)</strong> a Child is required to remain in hospital after the Child&#39;s birth, or is hospitalised immediately after the Child&#39;s birth, including because:</p><p>(1) the Child was born prematurely; or (2) the Child developed a complication or contracted an illness during the child&#39;s period of gestation or at birth; or (3) the Child developed a complication or contracted an illness following the Child&#39;s birth; and <strong>(B)</strong> an Employee, whether before or after the birth of the Child, gives notice in accordance with subclause</p><p><strong>59.6</strong> of the taking of a period of unpaid parental leave (the original leave period) in relation to the Child, then the Employee may agree with their Employer that the Employee will not take unpaid parental leave for a period (the permitted work period) while the Child remains in hospital.</p><p><strong>(ii)</strong> If the Employee and Employer so agree, then the following rules have effect: <strong>(A)</strong> the Employee is taken to not be taking unpaid parental leave during the permitted work period; <strong>(B)</strong> the permitted work period does not break the continuity of the original leave period; and <strong>(C)</strong> the Employee is taken to have advised the Employer, for the purposes of subclause 59.6(b), of an end date for the original leave period that is the date on which that period would end if it were extended by a period equal to the permitted work period.</p><p><strong>(iii)</strong> The permitted work period must start after the birth of the Child.</p><p><strong>(iv)</strong> The permitted work period ends at the earliest of the following: <strong>(A)</strong> the time agreed by the Employer and Employee; <strong>(B)</strong> the end of the day of the Child&#39;s first discharge from hospital after birth; or <strong>(C)</strong> if the Child dies before being discharged, the end of the day the Child dies.</p><p><strong>(v)</strong> Only one period may be agreed to under subclause 59.3(h)(i) for which the Employee will not take unpaid parental leave in relation to the Child.</p><p><strong>(vi)</strong> The Employee must, if required by the Employer, give the Employer evidence (including without limitation, a medical</p><p>certificate) that would satisfy a reasonable person of either or both of the following: <strong>(A)</strong> that subclause 59.3(h)(i)(A) applies in relation to the child; <strong>(B)</strong> that the Employee is fit for work.</p><p><strong>59.4</strong> Short Parental Leave – Unpaid</p><p><strong>(a)</strong> This clause applies to an Eligible Employee who is a member of an Employee Couple.</p><p><strong>(b)</strong> An Eligible Employee who will not be the Primary Carer of a Child may take up to eight weeks&#39; leave concurrently with any parental leave taken by the parent who will be the Primary Carer. Short Parental Leave may be taken in separate periods but, unless the Employer agrees, each period must not be shorter than two weeks.</p><p><strong>(c)</strong> The period of Short Parental Leave will be deducted from the period of Long Parental Leave to which the Eligible Employee is entitled under subclause 59.3(if applicable).</p><p><strong>59.5</strong> Paid Parental Leave</p><p><strong>(a)</strong> An Eligible Employee commencing parental leave is entitled to paid parental leave on the following basis:</p><p><strong>(i)</strong> until 31 March 2021: <strong>(A)</strong> a Primary Carer taking Long Parental Leave will be entitled to 10 weeks&#39; paid parental leave, provided that the Long Parental Leave is taken contemporaneously with the birth or placement of the Child (subject to clause 59.3(h), in which case the Employee taking Long Parental Leave may agree with the Employer that the Employee will not take Long Parental Leave during the permitted work period while the Child remains hospitalised); and <strong>(B)</strong> a non-Primary Carer taking Short Parental Leave will be entitled to one week&#39;s paid parental leave;</p><p><strong>(ii)</strong> from 1 April 2021 onwards: <strong>(A)</strong> a Primary Carer taking Long Parental Leave will be entitled to 14 weeks&#39; paid parental leave, provided that the Long Parental Leave is taken contemporaneously with the birth or placement of the Child (subject to clause 59.3(h), in which case the Employee taking Long Parental Leave may agree with the Employer that the Employee will not take Long Parental Leave during the permitted work period while the Child remains hospitalised); and</p><p><strong>(B)</strong> a non-Primary Carer taking Short Parental Leave will be entitled to two weeks&#39; paid parental leave, save that an Eligible Employee is not entitled to both paid Long Parental Leave and paid Short Parental Leave in respect of the same birth or adoption event. Paid parental leave is in addition to any relevant Commonwealth Government paid parental leave scheme (subject to the requirements of any applicable legislation)</p><p><strong>(b)</strong> The Employer and Eligible Employee may reach agreement as to how the paid parental leave under this Agreement is paid. For example, such leave may be paid in smaller amounts over a longer period, consecutively or concurrently with any relevant Commonwealth Government parental leave scheme (subject to the requirements of any applicable legislation) and may include a voluntary contribution to superannuation.</p><p><strong>(c)</strong> Such agreement must be in writing and signed by the parties. The Eligible Employee must nominate a preferred payment arrangement at least four weeks prior to the expected date of birth or date of placement of the Child. In the absence of agreement, such leave will be paid during the ordinary pay periods corresponding with the period of the leave.</p><p><strong>(d)</strong> Subject to <a href="/eba/ebas/has-managers-admin/common-terms/leave/61-long-service-leave.html">clause 61.2</a>(b)(ii) and 61.2(g) (in the case of long service leave), a variation to the payment of paid parental leave resulting in, for example, the paid leave being spread over more than 14 weeks does not affect the period of continuous service recognised. For example, an Employee taking 28 weeks at half pay will, for the purpose of calculating continuous service, have fourteen weeks of continuous service recognised. An Employee taking seven (7) weeks at double pay will have 14 weeks of continuous service recognised.</p><p><strong>(e)</strong> The paid parental leave prescribed by this clause will be concurrent with any relevant unpaid entitlement prescribed by the NES/this Agreement.</p><p><strong>59.6</strong> Notice and evidence requirements</p><p><strong>(a)</strong> Subject to clause 59.6(e) (Notice - Flexible Long Parental Leave), an Employee must give at least 10 weeks&#39; written notice of the intention to take parental leave, including the proposed start and end dates. At this time, the Employee must also provide a statutory declaration stating:</p><p><strong>(i)</strong> that the Employee will become either the Primary Carer or non-Primary Carer of the Child, as appropriate;</p><p><strong>(ii)</strong> the particulars of any parental leave taken or proposed to be taken or applied for by the Employee&#39;s Spouse; and</p><p><strong>(iii)</strong> that for the period of parental leave the Employee will not engage in any conduct inconsistent with their contract of employment.</p><p><strong>(b)</strong> Subject to clause 59.6(e) (Notice - Flexible Long Parental Leave), at least four weeks before the intended commencement of parental leave, the Employee must confirm in writing the intended start and end dates of the parental leave, or advise the Employer of any changes to the notice provided in subclause 59.6(a), unless it is not practicable to do so.</p><p><strong>(c)</strong> The Employer may require the Employee to provide evidence which would satisfy a reasonable person of:</p><p><strong>(i)</strong> in the case of birth-related leave: <strong>(A)</strong> the date of birth, or expected date of both, of the Child (including without limitation, a medical certificate or certificate from a registered midwife, stating the date of birth or expected date of birth); and <strong>(B)</strong> if relevant, that their Child was stillborn (including without limitation, a certification by a medical practitioner or registered midwife of the child as having been delivered); or</p><p><strong>(ii)</strong> in the case of adoption-related leave, the commencement of the placement (or expected day of placement) of the Child and that the Child will be under 16 years of age as at the day of placement or expected day of placement.</p><p><strong>(d)</strong> An Employee will not be in breach of this clause if failure to give the stipulated notice is occasioned by the birth of the Child or placement occurring earlier than the expected date or in other compelling circumstances. In these circumstances the notice and evidence requirements of this clause should be provided as soon as reasonably practicable.</p><p><strong>(e)</strong> Notice requirements - Flexible Long Parental Leave</p><p><strong>(i)</strong> If an Employee wishes to take Flexible Long Parental Leave, the Employee must give notice to the Employer as follows: <strong>(A)</strong> where the Employee also takes unpaid Long Parental Leave or Short Parental Leave under subclauses 59.3 or 59.4 (the original leave); (1) at the same time as the Employee gives notice in accordance with subclause 59.6(a) in relation to the original leave, unless subclause 2) below applies; or</p><p>(2) if the Employee takes more than one period of unpaid Short Parental Leave, at the same time as the Employee gives notice in accordance with subclause 59.6(a) in relation to the first of those periods of leave; or <strong>(B)</strong> otherwise - at least 10 weeks before starting the Flexible Long Parental Leave.</p><p><strong>(ii)</strong> If the Employer agrees, the notice may be given at a later time than that specified in subclause 59.6(e)(i).</p><p><strong>(iii)</strong> The notice under subclause 59.6(e)(i) must specify the total number of days (Flexible Days) of Flexible Long Parental Leave that the Employee intends to take in relation to the Child.</p><p><strong>(iv)</strong> If the Employer agrees, the Employee may: <strong>(A)</strong> reduce the number of flexible days, including by reducing the number of flexible days to zero; or <strong>(B)</strong> increase the number of flexible days, but not so as to increase the number of flexible days above 30.</p><p><strong>(v)</strong> The Employee must give the Employer written notice of a flexible day on which the Employee will take Flexible Long Parental Leave: <strong>(A)</strong> at least 4 weeks before that day; or <strong>(B)</strong> if that is not practicable, as soon as practicable (which may be a time after the leave has started).</p><p><strong>(vi)</strong> If the Employer agrees, the Employee may change a day on which the Employee takes Flexible Long Parental Leave from a day specified in a notice under subsection 59.6(e)(v).</p><p><strong>59.7</strong> Parental leave associated with the birth of a Child – additional provisions</p><p><strong>(a)</strong> Subject to the limits on duration of parental leave set out in this Agreement and unless agreed otherwise between the Employer and Eligible Employee, an Eligible Employee who is pregnant may commence Long Parental Leave at any time up to six weeks immediately prior to the expected date of birth.</p><p><strong>(b)</strong> Six weeks before the birth</p><p><strong>(i)</strong> Where a pregnant Eligible Employee continues to work during the six week period immediately prior to the expected date of birth, the Employer may require the Eligible Employee to provide a medical certificate stating that she is</p><p>fit for work and, if so, whether it is inadvisable for her to continue in her present position because of illness or risks arising out of the Eligible Employee&#39;s pregnancy or hazards connected with the position.</p><p><strong>(ii)</strong> Where a request is made under subclause 59.7(b)(i) and an Eligible Employee: <strong>(A)</strong> does not provide the Employer with the requested certificate within seven days of the request; or <strong>(B)</strong> within seven days after the request, the Eligible Employee gives the Employer a medical certificate stating that the Eligible Employee is not fit for work, <strong>(C)</strong> the Employer may require the Eligible Employee to commence their parental leave as soon as practicable.</p><p><strong>(iii)</strong> Where a request is made under subclause 59.7(b)(i) and an Eligible Employee provides a medical certificate that states that the Eligible Employee is fit for work but it is inadvisable for the Eligible Employee to continue in her present position during a stated period, subclause 59.14 (Transfer to a safe job) will apply.</p><p><strong>59.8</strong> Unpaid pre-adoption leave Employees&#39; entitlement to pre-adoption leave is set out at <a href="/eba/ebas/has-managers-admin/common-terms/leave/58-pre-adoption-leave.html">clause 58</a> (Pre-adoption leave).</p><p><strong>59.9</strong> Where placement does not proceed or continue</p><p><strong>(a)</strong> Where the placement of the Child for adoption with an Eligible Employee does not proceed or continue, the Eligible Employee must notify the Employer immediately.</p><p><strong>(b)</strong> Where the Eligible Employee had, at the time, started a period of adoption-related leave in relation to the placement, the Eligible Employee&#39;s entitlement to adoption related leave is not affected, except where the Employer gives written notice under subclause 59.9(c).</p><p><strong>(c)</strong> The Employer may give the Eligible Employee written notice that, from a stated day no earlier than four weeks after the day the notice is given, any untaken long adoption-related leave is cancelled with effect from that day.</p><p><strong>(d)</strong> Where the Eligible Employee wishes to return to work due to a placement not proceeding or continuing, the Employer must nominate a time not exceeding four weeks from receipt of notification for the Eligible Employee&#39;s return to work.</p><p><strong>59.10</strong> Special maternity leave</p><p><strong>(a)</strong> Entitlement to unpaid special birth-related leave</p><p><strong>(i)</strong> A female Eligible Employee is entitled to a period of unpaid special leave if she is not fit for work during that period because: <strong>(A)</strong> she has a pregnancy-related illness; or <strong>(B)</strong> all of the following apply: 1) she has been pregnant; and</p><p>2) the pregnancy ends after a period of gestation of at least 12 weeks otherwise than by the birth of a living Child or a Stillbirth.</p><p><strong>(ii)</strong> A female Eligible Employee who has an entitlement to personal leave may, in part or whole, take personal leave instead of unpaid special leave under this clause.</p><p><strong>(iii)</strong> Where the pregnancy ends more than 28 weeks from the expected date of birth of the Child, the Eligible Employee is entitled to access any paid and/or unpaid personal leave entitlements in accordance with the relevant personal leave provisions.</p><p><strong>(b)</strong> Entitlement to paid special birth-related leave</p><p><strong>(i)</strong> A female Eligible Employee is entitled to a period of paid special leave if the pregnancy terminates at or after the completion of 20 weeks&#39; gestation or the Eligible Employee gives birth but the baby subsequently dies.</p><p><strong>(ii)</strong> Paid special leave is paid leave not exceeding the amount of paid leave available to Primary Carers under subclause 59.5(a)(i)(A) or 59.5(a)(ii)(A) (plus superannuation).</p><p><strong>(iii)</strong> Paid special leave is in addition to any unpaid special leave taken under subclause 59.10(a)(i).</p><p><strong>(iv)</strong> Paid leave available to non-Primary Carers under subclause 59.5(a)(i)(B) or 59.5(a)(ii)(B) will also apply in these circumstances.</p><p><strong>(c)</strong> Evidence If an Eligible Employee takes leave under this clause the Employer may require the Eligible Employee to provide evidence that would satisfy a reasonable person of the matters referred to in subclause 59.10(a)(i) or 59.10(b)(i) or to provide a certificate from a registered medical practitioner. The Eligible Employee must give notice to the Employer as soon as practicable, advising the Employer of the period or the expected period of the leave under this provision.</p><p><strong>59.11</strong> Variation of period of unpaid parental leave (up to 12 months)</p><p><strong>(a)</strong> Where an Eligible Employee has:</p><p><strong>(i)</strong> given notice of the taking of a period of Long Parental Leave under subclause 59.3; and</p><p><strong>(ii)</strong> the length of this period of Long Parental Leave as notified to the Employer is less than the Eligible Employee&#39;s available entitlement to Long Parental Leave; and</p><p><strong>(iii)</strong> commenced the period of Long Parental Leave; and</p><p><strong>(iv)</strong> not taken a period of Flexible Long Parental Leave, the Eligible Employee may extend the period of unpaid parental leave (up to the Eligible Employee&#39;s available entitlement to Long Parental Leave) by giving their Employer notice in writing of the extension and specifying the new end date for the leave. This one-off extension is to be notified as soon as possible but no less than four weeks before the end date of the original leave period. Nothing in this clause detracts from the basic entitlement in subclause 59.3 (Long Parental Leave – Unpaid) or subclause 59.12 (Right to request an extension of period of unpaid parental leave beyond 12 months).</p><p><strong>(b)</strong> If the Employer and Eligible Employee agree, the Eligible Employee may further extend, or reduce the period of parental leave.</p><p><strong>59.12</strong> Right to request an extension of period of unpaid parental leave beyond 12 months</p><p><strong>(a)</strong> An Eligible Employee entitled to Long Parental Leave pursuant to the provisions of subclause 59.3 may request the Employer to allow the Eligible Employee to extend the period of Long Parental Leave by a further continuous period of up to 12 months immediately following the end of the available parental leave.</p><p><strong>(b)</strong> Request to be in writing The request must be in writing and must be given to the Employer at least four weeks before the end of the available parental leave period.</p><p><strong>(c)</strong> Response to be in writing The Employer must give the Eligible Employee a written response to the request stating whether the Employer grants or refuses the request. The response must be given as soon as practicable, and not later than 21 days, after the request is made.</p><p><strong>(d)</strong> Refusal only on reasonable business grounds The Employer may only refuse the request on reasonable business grounds.</p><p><strong>(e)</strong> Reasons for refusal to be specified If the Employer refuses the request, the written response must include details of the reasons for the refusal.</p><p><strong>(f)</strong> Reasonable opportunity to discuss The Employer must not refuse the request unless the Employer has given the Eligible Employee a reasonable opportunity to discuss the request.</p><p><strong>(g)</strong> Employee Couples Where a member of an Employee Couple is requesting an extension to a period of Long Parental Leave in relation to a Child:</p><p><strong>(i)</strong> the request must specify any amount of Long Parental Leave that the other member of the Employee Couple has taken, or will have taken in relation to the Child before the extension starts;</p><p><strong>(ii)</strong> if the other member of the Employee Couple has given notice of an intention to take Flexible Long Parental Leave (in accordance with subclause 59.6(e)), the request must specify the number of flexible days that will not have been taken when the period of extended leave commences;</p><p><strong>(iii)</strong> the period of extension cannot exceed 12 months, less any period of Long Parental Leave (other than Flexible Long Parental Leave) that the other member of the Employee Couple has taken, or will have taken, in relation to the Child before the extension starts, as well as a period equal to the other member&#39;s Notional Flexible Period (if subparagraph 59.12(g)(iii) applies above); and</p><p><strong>(iv)</strong> the amount of Long Parental Leave to which the other member of the Employee Couple is entitled under subclause</p><p><strong>59.3</strong> in relation to the Child is reduced by the period of the extension.</p><p><strong>(h)</strong> No extension beyond 24 months An Eligible Employee is not entitled to extend the period of Long Parental Leave beyond 24 months after the date of birth or day of placement of the Child.</p><p><strong>59.13</strong> Parental leave and other entitlements An Eligible Employee may use any accrued annual leave or long service leave entitlements concurrently with Long Parental Leave, save that taking that leave does not have the effect of extending the period of Long Parental Leave.</p><p><strong>59.14</strong> Transfer to a safe job</p><p><strong>(a)</strong> Where an Employee is pregnant and provides evidence that would satisfy a reasonable person that she is fit for work but it is inadvisable for the Employee to continue in her present position for a stated period (the risk period) because of:</p><p><strong>(i)</strong> illness or risks arising out of the pregnancy, or</p><p><strong>(ii)</strong> hazards connected with the position, the Employee must be transferred to an appropriate safe job if one is available for the risk period, with no other change to the Employee&#39;s terms and conditions of employment.</p><p><strong>(b)</strong> Paid no safe job leave If:</p><p><strong>(i)</strong> subclause 59.14(a) applies to a pregnant Eligible Employee but there is no appropriate safe job available;</p><p><strong>(ii)</strong> the Eligible Employee is entitled to Long Parental Leave; and</p><p><strong>(iii)</strong> the Eligible Employee has complied with the notice of intended start and end dates of leave and evidence requirements under subclause 59.6 for taking Long Parental Leave, then the Eligible Employee is entitled to paid no safe job leave for the risk period.</p><p><strong>(c)</strong> If the Eligible Employee takes paid no safe job leave for the risk period, the Employer must pay the Eligible Employee at the Eligible Employee&#39;s base rate of pay for the Eligible Employee&#39;s ordinary hours of work in the risk period.</p><p><strong>(d)</strong> This entitlement to paid no safe job leave is in addition to any other leave entitlement the Eligible Employee may have.</p><p><strong>(e)</strong> If an Eligible Employee, during the six week period before the expected date of birth, is on paid no safe job leave, the Employer may request that the Eligible Employee provide a medical certificate within seven (7) days stating whether the Eligible Employee is fit for work.</p><p><strong>(f)</strong> If, the Eligible Employee has either:</p><p><strong>(i)</strong> not complied with the request from the Employer under (e) above; or</p><p><strong>(ii)</strong> provided a medical certificate stating that she is not fit for work,</p><p>then the Eligible Employee is not entitled to no safe job leave and the Employer may require the Eligible Employee to take parental leave as soon as practicable.</p><p><strong>(g)</strong> Unpaid no safe job leave If:</p><p><strong>(i)</strong> subclause 59.14(a) applies to a pregnant Employee but there is no appropriate safe job available;</p><p><strong>(ii)</strong> the Employee will not be entitled to Long Parental Leave as at the expected date of birth; and</p><p><strong>(iii)</strong> the Employee has given the Employer evidence that would satisfy a reasonable person of the pregnancy if required by the Employer (which may include a requirement to provide a medical certificate),</p><p><strong>(iv)</strong> the Employee is entitled to unpaid no safe job leave for the risk period.</p><p><strong>59.15</strong> Returning to work after a period of parental leave</p><p><strong>(a)</strong> An Eligible Employee must confirm to the Employer that the Eligible Employee will return to work as scheduled after a period of Long Parental Leave at least four weeks prior to the end of the leave, or where that is not practicable, as soon as practicable.</p><p><strong>(b)</strong> An Eligible Employee will be entitled to return:</p><p><strong>(i)</strong> unless subclause 59.15(b)(ii) or subclause 59.15(b)(iii) applies, to the position which they held immediately before proceeding on parental leave;</p><p><strong>(ii)</strong> if the Eligible Employee was promoted or voluntarily transferred to a new position (other than to a safe job pursuant to subclause 59.14), to the new position;</p><p><strong>(iii)</strong> if subclause 59.15(b)(ii) does not apply, and the Eligible Employee began working part-time because of the pregnancy of the Eligible Employee, or their Spouse, to the position held immediately before starting to work part-time.</p><p><strong>(c)</strong> Subclause 59.15(b) is not to result in the Eligible Employee being returned to the safe job to which the Eligible Employee was transferred under subclause 59.14. In such circumstances, the Eligible Employee will be entitled to return to the position held immediately before the transfer.</p><p><strong>(d)</strong> Where the relevant former position (per subclauses 59.15(b) and 59.15(c) above) no longer exists, an Eligible Employee is entitled to return to an available position for which the Eligible Employee is</p><p>qualified and suited nearest in status and pay to that of their pre- parental leave position.</p><p><strong>(e)</strong> The Employer must not fail to re-engage an Eligible Employee because:</p><p><strong>(i)</strong> the Eligible Employee or Eligible Employee&#39;s Spouse is pregnant; or</p><p><strong>(ii)</strong> the Eligible Employee is or has been immediately absent on parental leave.</p><p><strong>(f)</strong> The rights of the Employer in relation to engagement and re- engagement of casual Employees are not affected, other than in accordance with this clause.</p><p><strong>(g)</strong> Stillbirth or death of child – cancelling leave or returning to work</p><p><strong>(i)</strong> In the event of a Stillbirth, or if a Child dies during the 24- month period starting on the child&#39;s date of birth, then an Eligible Employee who is entitled to a period of unpaid parental leave in relation to the Child may: <strong>(A)</strong> before the period of leave starts, give their Employer written notice cancelling the leave; or <strong>(B)</strong> if the period of leave has started, give their Employer written notice that the Employee wishes to return to work on a specified day (which must be at least 4 weeks after the date on which the Employer receives the notice).</p><p><strong>(ii)</strong> Where notice under subclause 59.15(g)(i) is given, the Employee&#39;s entitlement to Long Parental Leave in relation to the Child ends: <strong>(A)</strong> if the action is taken under subclause 59.15(g)(i)(A), immediately after the cancellation of the leave; or <strong>(B)</strong> if the action is taken under subclause 59.15(g)(i)(B), immediately before the specified day.</p><p><strong>(iii)</strong> This subclause 59.15(g) does not limit subclause 59.11(b) (dealing with the Employee reducing the period of unpaid parental leave with the agreement of the Employer).</p><p><strong>(h)</strong> Employee who ceases to have responsibility for care of Child</p><p><strong>(i)</strong> This subclause applies to an Employee who has taken unpaid Long Parental Leave in relation to a Child if the Employee ceases to have any responsibility for the care of the Child for a reason other than because: <strong>(A)</strong> of a Stillbirth; or</p><p><strong>(B)</strong> the Child dies during the 24-month period starting on the child&#39;s date of birth.</p><p><strong>(ii)</strong> The Employer may give the Employee written notice requiring the Employee to return to work on a specified day.</p><p><strong>(iii)</strong> The specified day: <strong>(A)</strong> must be at least 4 weeks after the notice is given to the Employee; and <strong>(B)</strong> if the leave is birth-related leave taken by a female Employee who has given birth, must not be earlier than 6 weeks after the date of birth of the Child.</p><p><strong>(iv)</strong> The Employee&#39;s entitlement to Long Parental Leave in relation to the Child ends immediately before the specified day.</p><p><strong>59.16</strong> Replacement Employees</p><p><strong>(a)</strong> A replacement Employee is an Employee specifically engaged or temporarily promoted or transferred, as a result of an Eligible Employee proceeding on parental leave.</p><p><strong>(b)</strong> Before the Employer engages a replacement Employee, the Employer must inform that person of the temporary nature of the employment and of the rights of the Eligible Employee who is being replaced to return to their pre-parental leave position.</p><p><strong>59.17</strong> Communication during parental leave – organisational change</p><p><strong>(a)</strong> Where an Eligible Employee is on parental leave and the Employer proposes a change that will have a significant effect within the meaning of <a href="/eba/ebas/has-managers-admin/common-terms/consultation-disputes/16-consultation.html">clause 16</a> (Consultation) of this Agreement on the Eligible Employee&#39;s pre-parental leave position, the Employer will comply with the requirements of <a href="/eba/ebas/has-managers-admin/common-terms/consultation-disputes/16-consultation.html">clause 16</a> (Consultation) which include but are not limited to providing:</p><p><strong>(i)</strong> information in accordance with subclause 16.4; and</p><p><strong>(ii)</strong> an opportunity for discussions with the Eligible Employee and, where applicable, the Eligible Employee&#39;s representative in accordance with subclause 16.6.</p><p><strong>(b)</strong> The Eligible Employee will take reasonable steps to inform the Employer about any significant matter that arises whilst the Eligible Employee is taking parental leave that will affect the Eligible Employee&#39;s decision regarding the duration of parental leave to be taken, whether the Eligible Employee intends to return to work and whether the Eligible Employee intends to request to return to work on a part-time basis.</p><p><strong>(c)</strong> The Eligible Employee will also notify the Employer of changes of address or other contact details which might affect the Employer&#39;s capacity to comply with subclause 59.17.</p><p><strong>59.18</strong> Keeping in touch days</p><p><strong>(a)</strong> This clause does not prevent an Eligible Employee from performing work for the Employer on a keeping in touch day while the Eligible Employee is taking Long Parental Leave. If the Eligible Employee does so, the performance of that work does not break the continuity of the period of Long Parental Leave.</p><p><strong>(b)</strong> Any day or part of a day on which the Eligible Employee performs work for the Employer during the period of leave is a keeping in touch day if:</p><p><strong>(i)</strong> the purpose of performing the work is to enable the Eligible Employee to keep in touch with their employment in order to facilitate a return to that employment after the end of the period of leave;</p><p><strong>(ii)</strong> both the Eligible Employee and Employer consent to the Eligible Employee performing work for the Employer on that day; and</p><p><strong>(iii)</strong> the day is not within: <strong>(A)</strong> if the Eligible Employee suggested or requested that they perform work for the Employer on that day - 14 days after the date of birth, or day of placement, of the Child to which the period of leave relates; or <strong>(B)</strong> otherwise - 42 days after the date of birth, or day of placement, of the Child; and</p><p><strong>(iv)</strong> the Eligible Employee has not already performed work for the Employer or another entity on ten days during the period of leave that were keeping in touch days, subject to (d)(ii) below.</p><p><strong>(c)</strong> The Employer must not exert undue influence or undue pressure on an Eligible Employee to consent to a keeping in touch day.</p><p><strong>(d)</strong> For the purposes of subclause 59.18(b)(iv) the following will be treated as two separate periods of unpaid parental leave (meaning that an Eligible Employee can work up to ten keeping in touch days during each period of leave):</p><p><strong>(i)</strong> a period of Long Parental Leave taken during the Eligible Employee&#39;s available parental leave period under subclause</p><p><strong>59.3</strong> (Long Parental Leave – Unpaid) and 59.11 (Variation of period of unpaid parental leave (up to 12 months)); and</p><p><strong>(ii)</strong> an extension of the period of Long Parental Leave under subclause 59.12 (Right to request an extension of period of unpaid parental leave beyond 12 months),</p><p><strong>(e)</strong> Subclause 59.18(a) does not apply in relation to the Eligible Employee on and after the first day on which the Employee takes flexible unpaid parental leave in relation to the Child.</p><p>Plain language terms: maternity leave, paternity leave, baby leave, adoption leave.</p>',216)])])}const u=t(i,[["render",r]]);export{m as __pageData,u as default};
